const fmt=(v)=>{if(!v&&v!==0)return"R$ 0,00";return"R$ "+Math.abs(v).toLocaleString("pt-BR",{minimumFractionDigits:2,maximumFractionDigits:2});};
const p100=(v)=>Math.round(v*100)+"%";
const sob=(n)=>{const p=n.trim().split(" ");return p.length>1?p[p.length-1]:"";};
const waLink=(t)=>{const n=(t||"").replace(/\D/g,"");if(!n)return null;return"https://wa.me/"+(n.startsWith("55")?n:"55"+n);};
const isEnt=(t)=>t==="entrada";

function calcC(c){
  const v=c.valorAcao||0;
  // Total honorários = % honorários × valor atualizado da ação
  const honTot=v*(c.pctHon||0);
  // Antecipado: valor fixo já recebido (digitado manualmente)
  const antec=c.valorAntecipado>0 ? c.valorAntecipado : honTot*(c.pctAntec||0.15);
  // Restante: % restante × total honorários ATUALIZADO
  // Ex: 18% × (25% × R$20.955,07) = 18% × R$5.238,77 = R$942,98
  const rest=honTot*(c.pctRestante||0.18);
  const honP1=rest*(c.p1Hon||0);
  const honP2=rest*(c.p2Hon||0);
  const honDel=rest*(c.pctDelHon||0);
  const honGm=honDel*(c.pctGm||0.5);
  const honBo=honDel*(c.pctBo||0.5);
  const antiDel=antec*(c.pctDelHon||0);
  const antiGm=antiDel*(c.pctGm||0.5);
  const antiBo=antiDel*(c.pctBo||0.5);
  const sucTot=v*(c.pctSucumb||0);
  const sucP1=sucTot*(c.p1Suc||0);
  const sucP2=sucTot*(c.p2Suc||0);
  const sucDel=sucTot*(c.pctDelSuc||0);
  const sucGm=sucDel*(c.pctGm||0.5);
  const sucBo=sucDel*(c.pctBo||0.5);
  return{honTot,antec,rest,honP1,honP2,honDel,honGm,honBo,antiDel,antiGm,antiBo,sucTot,sucP1,sucP2,sucDel,sucGm,sucBo};
}

