function Lbl({ch}){return <div style={{fontSize:10,color:"#64748b",fontWeight:600,marginBottom:5,letterSpacing:0.5,textTransform:"uppercase"}}>{ch}</div>;}
function Row({l,v,c,b,sub}){return <div style={{display:"flex",justifyContent:"space-between",padding:"4px 0",borderBottom:"1px solid #1a2535"}}><span style={{fontSize:11,color:"#64748b"}}>{l}{sub&&<span style={{fontSize:10,color:"#4a5568",marginLeft:4}}>{sub}</span>}</span><span style={{fontSize:11,fontWeight:b?800:600,color:c||"#e2e8f0"}}>{v}</span></div>;}
function Pct({label,value,onChange,color,baseVal}){
  const pctNum = Math.round(value*100);
  const valReais = baseVal!=null ? Math.round(baseVal*value*100)/100 : null;
  return(
    <div style={{marginBottom:12}}>
      <div style={{fontSize:11,color:"#64748b",marginBottom:6}}>{label}</div>
      <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:6}}>
        <div style={{display:"flex",alignItems:"center",gap:4,flex:1}}>
          <span style={{fontSize:11,color:"#64748b",whiteSpace:"nowrap"}}>%</span>
          <input
            type="number" min={0} max={100} step={1}
            value={pctNum}
            onChange={e=>{const v=Math.min(100,Math.max(0,parseInt(e.target.value)||0));onChange(v/100);}}
            style={{width:"100%",background:"#0f1117",border:"1px solid #2d3748",borderRadius:7,padding:"7px 10px",color:color||"#6366f1",fontSize:14,fontWeight:800,outline:"none",textAlign:"center"}}
          />
          <span style={{fontSize:14,color:color||"#6366f1",fontWeight:800}}>%</span>
        </div>
        {baseVal!=null&&(
          <div style={{display:"flex",alignItems:"center",gap:4,flex:2}}>
            <span style={{fontSize:11,color:"#64748b",whiteSpace:"nowrap"}}>R$</span>
            <input
              type="number"
              value={valReais??0}
              onChange={e=>{const v=parseFloat(e.target.value)||0;if(baseVal>0)onChange(Math.min(1,Math.max(0,Math.round((v/baseVal)*1000)/1000)));}}
              style={{width:"100%",background:"#0f1117",border:"1px solid #2d3748",borderRadius:7,padding:"7px 10px",color:"#e2e8f0",fontSize:13,fontWeight:600,outline:"none",textAlign:"right"}}
            />
          </div>
        )}
      </div>
      <input type="range" min={0} max={100} step={1} value={pctNum} onChange={e=>onChange(parseInt(e.target.value)/100)} style={{width:"100%",accentColor:color||"#6366f1",cursor:"pointer",margin:0,height:4}}/>
    </div>
  );
}

function Card({label,value,color,sub}){return <div style={{background:"#1a1d2e",borderRadius:12,padding:"12px 14px",border:"1px solid #2d3748"}}><div style={{fontSize:10,color:"#64748b",fontWeight:600,letterSpacing:0.5,textTransform:"uppercase",marginBottom:3}}>{label}</div><div style={{fontSize:15,fontWeight:800,color}}>{value}</div>{sub&&<div style={{fontSize:10,color:"#64748b",marginTop:2}}>{sub}</div>}</div>;}
function MiniBar({pct,color}){return <div style={{height:4,background:"#1e2a3a",borderRadius:2,overflow:"hidden",marginTop:5}}><div style={{height:"100%",width:`${Math.min(100,pct||0)}%`,background:color,borderRadius:2}}/></div>;}
function Badge({tipo}){const t=TIPO_FIN_LABELS[tipo]||{};return <span style={{background:t.bg,color:t.color,borderRadius:6,padding:"2px 8px",fontSize:10,fontWeight:700,whiteSpace:"nowrap"}}>{t.icon} {t.label}</span>;}
function Toggle({on,onToggle,label,color}){return <div style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer"}} onClick={onToggle}><div style={{width:36,height:20,borderRadius:10,background:on?color||"#6366f1":"#2d3748",position:"relative",transition:"background 0.2s",flexShrink:0}}><span style={{position:"absolute",top:2,left:on?18:2,width:16,height:16,borderRadius:"50%",background:"#fff",transition:"left 0.2s"}}/></div><span style={{fontSize:12,fontWeight:700,color:on?color||"#818cf8":"#64748b"}}>{label}</span></div>;}

const inp={width:"100%",background:"#0f1117",border:"1px solid #2d3748",borderRadius:8,padding:"9px 12px",color:"#e2e8f0",fontSize:13,outline:"none",boxSizing:"border-box"};
const sel={...inp,cursor:"pointer"};

const EC={nome:"",cpf:"",dataNasc:"",telefone:"",email:"",endereco:"",cidade:"",uf:"",tese:"OBRA",status:"CONVERSANDO",fase:"CONHECIMENTO",processo:"",vara:"",comarca:"",parteContraria:"",advPC:"",valorAcao:0,semGilrat:0,pctHon:0.25,pctSucumb:0.1,pctAntec:0.15,temP1:true,nomeP1:"",tipoP1:"Escritório Jurídico",p1Hon:0.7,p1Suc:0.7,temP2:false,nomeP2:"",tipoP2:"Contabilidade",p2Hon:0,p2Suc:0,pctDelHon:0.3,pctDelSuc:0.3,pctGm:0.5,pctBo:0.5,obs:""};
const EL={tipo:"entrada",cat:"Honorários Antecipado",desc:"",valor:"",data:`${ANO_AT}-${dd(MES_AT+1)}-${dd(hoje.getDate())}`,mes:MES_AT,ano:ANO_AT};

// ═══════════════════════════════════════════════════════════════
// APP PRINCIPAL
// ═══════════════════════════════════════════════════════════════
export default function App(){
  // Estado CRM
  const [clients,setClients]=useState(CLIENTES_INI);
  const [selC,setSelC]=useState(null);
  const [showFC,setShowFC]=useState(false);
  const [formC,setFormC]=useState(EC);
  const [editC,setEditC]=useState(null);
  const [abaFC,setAbaFC]=useState("cliente");
  const [srch,setSrch]=useState("");
  const [fSt,setFSt]=useState("TODOS");
  const [fTe,setFTe]=useState("TODOS");
  // Estado Financeiro
  const [lancs,setLancs]=useState(LANC_INI);
  const [mes,setMes]=useState(MES_AT);
  const [ano,setAno]=useState(ANO_AT);
  const [showFL,setShowFL]=useState(false);
  const [formL,setFormL]=useState(EL);
  const [editL,setEditL]=useState(null);
  const [fTipo,setFTipo]=useState("todos");
  const [abaFin,setAbaFin]=useState("resumo");
  // Navegação principal
  const [nav,setNav]=useState("crm");

  // ── Cálculos CRM ──
  const filtered=useMemo(()=>clients.filter(c=>{
    const q=srch.toLowerCase();
    const m=c.nome.toLowerCase().includes(q)||c.cidade.toLowerCase().includes(q)||sob(c.nome).toLowerCase().includes(q)||(c.cpf||"").includes(q)||(c.processo||"").includes(q)||(c.comarca||"").toLowerCase().includes(q)||(c.nomeP1||"").toLowerCase().includes(q);
    return m&&(fSt==="TODOS"||c.status===fSt)&&(fTe==="TODOS"||c.tese===fTe);
  }),[clients,srch,fSt,fTe]);

  const crmTotais=useMemo(()=>{
    let tDel=0,tGm=0,tBo=0,tAnti=0;
    clients.forEach(c=>{const r=calcC(c);tDel+=r.honDel+r.sucDel;tGm+=r.honGm+r.sucGm;tBo+=r.honBo+r.sucBo;tAnti+=r.antiGm+r.antiBo;});
    return{tDel,tGm,tBo,tAnti};
  },[clients]);

  const conn=useMemo(()=>{
    if(!selC)return{cidade:[],sob:[]};
    const sb=sob(selC.nome).toLowerCase();
    const cd=(selC.cidade||"").toLowerCase();
    return{cidade:cd?clients.filter(c=>c.id!==selC.id&&(c.cidade||"").toLowerCase()===cd):[],sob:sb.length>3?clients.filter(c=>c.id!==selC.id&&sob(c.nome).toLowerCase()===sb):[]};
  },[selC,clients]);

  // ── Cálculos Financeiro ──
  const doMes=useMemo(()=>lancs.filter(l=>l.mes===mes&&l.ano===ano),[lancs,mes,ano]);
  const filtLancs=useMemo(()=>fTipo==="todos"?doMes:doMes.filter(l=>l.tipo===fTipo),[doMes,fTipo]);

  const finTotais=useMemo(()=>{
    const ent=doMes.filter(l=>isEnt(l.tipo)).reduce((s,l)=>s+(l.valor||0),0);
    const fEmp=doMes.filter(l=>l.tipo==="fixa_empresa").reduce((s,l)=>s+(l.valor||0),0);
    const fGm=doMes.filter(l=>l.tipo==="fixa_guima").reduce((s,l)=>s+(l.valor||0),0);
    const fBo=doMes.filter(l=>l.tipo==="fixa_boaro").reduce((s,l)=>s+(l.valor||0),0);
    const vEmp=doMes.filter(l=>l.tipo==="var_empresa").reduce((s,l)=>s+(l.valor||0),0);
    const vGm=doMes.filter(l=>l.tipo==="var_guima").reduce((s,l)=>s+(l.valor||0),0);
    const vBo=doMes.filter(l=>l.tipo==="var_boaro").reduce((s,l)=>s+(l.valor||0),0);
    const sai=fEmp+fGm+fBo+vEmp+vGm+vBo;
    return{ent,fEmp,fGm,fBo,vEmp,vGm,vBo,sai,saldo:ent-sai,sGm:fGm+vGm+(fEmp+vEmp)/2,sBo:fBo+vBo+(fEmp+vEmp)/2};
  },[doMes]);

  const hist=useMemo(()=>{
    const arr=[];
    for(let i=5;i>=0;i--){let m=MES_AT-i,a=ANO_AT;if(m<0){m+=12;a--;}const its=lancs.filter(l=>l.mes===m&&l.ano===a);const e=its.filter(l=>isEnt(l.tipo)).reduce((s,l)=>s+(l.valor||0),0);const s=its.filter(l=>!isEnt(l.tipo)).reduce((s,l)=>s+(l.valor||0),0);arr.push({mes:m,ano:a,label:MESES[m].substring(0,3),e,s,saldo:e-s});}
    return arr;
  },[lancs]);
  const maxH=Math.max(...hist.map(h=>Math.max(h.e,h.s)),1);

  // ── Helpers form ──
  function sc(k,v){setFormC(f=>({...f,[k]:v}));}
  function sl(k,v){setFormL(f=>({...f,[k]:v}));}

  function setPH(campo,val){
    setFormC(f=>{
      const n={...f,[campo]:val};
      if(campo==="p1Hon"||campo==="p2Hon"){const p1=campo==="p1Hon"?val:f.p1Hon;const p2=campo==="p2Hon"?val:f.p2Hon;n.pctDelHon=Math.max(0,Math.round((1-p1-p2)*100)/100);}
      if(campo==="pctDelHon"){const r=Math.max(0,Math.round((1-val)*100)/100);n.p1Hon=f.temP2?Math.round(r*(f.p1Hon/(f.p1Hon+f.p2Hon||1))*100)/100:r;n.p2Hon=f.temP2?Math.round((r-n.p1Hon)*100)/100:0;}
      return n;
    });
  }
  function setPS(campo,val){
    setFormC(f=>{
      const n={...f,[campo]:val};
      if(campo==="p1Suc"||campo==="p2Suc"){const p1=campo==="p1Suc"?val:f.p1Suc;const p2=campo==="p2Suc"?val:f.p2Suc;n.pctDelSuc=Math.max(0,Math.round((1-p1-p2)*100)/100);}
      if(campo==="pctDelSuc"){const r=Math.max(0,Math.round((1-val)*100)/100);n.p1Suc=f.temP2?Math.round(r*(f.p1Suc/(f.p1Suc+f.p2Suc||1))*100)/100:r;n.p2Suc=f.temP2?Math.round((r-n.p1Suc)*100)/100:0;}
      return n;
    });
  }

  function saveC(){if(!formC.nome.trim())return;if(editC){setClients(p=>p.map(c=>c.id===editC?{...formC,id:editC}:c));}else{setClients(p=>[...p,{...formC,id:Date.now()}]);}setShowFC(false);}
  function openNewC(){setFormC({...EC});setEditC(null);setAbaFC("cliente");setShowFC(true);}
  function openEditC(c){setFormC({...c});setEditC(c.id);setAbaFC("cliente");setShowFC(true);setSelC(null);}
  function delC(id){setClients(p=>p.filter(c=>c.id!==id));setSelC(null);}
  function updSt(id,status){setClients(p=>p.map(c=>c.id===id?{...c,status}:c));setSelC(p=>p?{...p,status}:null);}

  function saveL(){if(!formL.desc.trim()||!formL.valor)return;const l={...formL,valor:parseFloat(formL.valor)||0};if(editL){setLancs(p=>p.map(x=>x.id===editL?{...l,id:editL}:x));}else{setLancs(p=>[...p,{...l,id:Date.now()}]);}setShowFL(false);}
  function openNewL(){const dt=`${ano}-${dd(mes+1)}-${dd(hoje.getDate())}`;setFormL({...EL,mes,ano,data:dt});setEditL(null);setShowFL(true);}
  function openEditL(l){setFormL({...l});setEditL(l.id);setShowFL(true);}
  function delL(id){setLancs(p=>p.filter(x=>x.id!==id));}
  function navMes(d){let m=mes+d,a=ano;if(m>11){m=0;a++;}if(m<0){m=11;a--;}setMes(m);setAno(a);}

  const selR=selC?calcC(selC):null;
  const fmR=formC.valorAcao>0?calcC(formC):null;

  // ═══════════════════════════════════════════════════════════════
  // RENDER
  // ═══════════════════════════════════════════════════════════════
  return(
    <div style={{fontFamily:"'DM Sans','Segoe UI',sans-serif",background:"#0f1117",minHeight:"100vh",color:"#e2e8f0"}}>

      {/* ── HEADER PRINCIPAL ── */}
      <div style={{background:"linear-gradient(135deg,#1a1d2e,#16213e)",borderBottom:"1px solid #2d3748",padding:"0 20px"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",maxWidth:1500,margin:"0 auto",height:58}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <div style={{width:34,height:34,borderRadius:10,background:"linear-gradient(135deg,#6366f1,#8b5cf6)",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:900,color:"#fff",fontSize:16}}>D</div>
            <div><div style={{fontWeight:800,fontSize:15,color:"#f1f5f9"}}>DELEGOO</div><div style={{fontSize:10,color:"#64748b"}}>{clients.length} clientes · {clients.filter(c=>c.status==="FECHADO").length} fechados</div></div>
          </div>
          <div style={{display:"flex",gap:4,background:"#0f1117",borderRadius:10,padding:4}}>
            {[["crm","📋 CRM"],["financeiro","💰 Financeiro"],["dashboard","📊 Dashboard"]].map(([v,l])=>(
              <button key={v} onClick={()=>setNav(v)} style={{padding:"7px 16px",borderRadius:8,border:"none",cursor:"pointer",fontWeight:700,fontSize:12,background:nav===v?"linear-gradient(135deg,#6366f1,#8b5cf6)":"transparent",color:nav===v?"#fff":"#64748b"}}>{l}</button>
            ))}
          </div>
          {nav==="crm"&&<button onClick={openNewC} style={{background:"linear-gradient(135deg,#6366f1,#8b5cf6)",color:"#fff",border:"none",borderRadius:10,padding:"9px 18px",fontWeight:700,fontSize:12,cursor:"pointer"}}>+ Novo Cliente</button>}
          {nav==="financeiro"&&<button onClick={openNewL} style={{background:"linear-gradient(135deg,#10b981,#059669)",color:"#fff",border:"none",borderRadius:10,padding:"9px 18px",fontWeight:700,fontSize:12,cursor:"pointer"}}>+ Lançamento</button>}
          {nav==="dashboard"&&<div style={{width:140}}/>}
        </div>
      </div>

      {/* ══════════════════════════════════════════════════════════
          MÓDULO CRM
      ══════════════════════════════════════════════════════════ */}
      {nav==="crm"&&(
        <div style={{maxWidth:1500,margin:"0 auto",padding:"14px 20px 24px"}}>
          {/* Cards resumo CRM */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:14}}>
            <Card label="Total Delegoo (CRM)" value={fmt(crmTotais.tDel)} color="#6366f1" sub="Honorários + Sucumbência"/>
            <Card label="Antecipado (15%)" value={fmt(crmTotais.tAnti)} color="#10b981" sub="A receber no fechamento"/>
            <Card label="Guima Total" value={fmt(crmTotais.tGm)} color="#22d3ee"/>
            <Card label="Boaro Total" value={fmt(crmTotais.tBo)} color="#f59e0b"/>
          </div>

          <div style={{display:"flex",gap:14}}>
            <div style={{flex:1,minWidth:0}}>
              {/* Filtros */}
              <div style={{display:"flex",gap:8,marginBottom:12,flexWrap:"wrap"}}>
                <input placeholder="🔍 Buscar nome, sobrenome, cidade, CPF, processo, comarca..." value={srch} onChange={e=>setSrch(e.target.value)} style={{flex:1,minWidth:200,...inp,borderRadius:10}}/>
                <select value={fSt} onChange={e=>setFSt(e.target.value)} style={{...sel,minWidth:160}}><option value="TODOS">Todos os status</option>{SL.map(s=><option key={s} value={s}>{s}</option>)}</select>
                <select value={fTe} onChange={e=>setFTe(e.target.value)} style={{...sel,minWidth:120}}><option value="TODOS">Todas as teses</option>{TL.map(t=><option key={t} value={t}>{t}</option>)}</select>
              </div>

              {/* Tabela */}
              <div style={{background:"#1a1d2e",borderRadius:14,border:"1px solid #2d3748",overflow:"hidden"}}>
                <div style={{overflowX:"auto"}}>
                  <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                    <thead><tr style={{background:"#16213e",borderBottom:"1px solid #2d3748"}}>
                      {["TESE","STATUS","CLIENTE","CIDADE/UF","PROCESSO / FASE","PARCEIROS","VLR AÇÃO","ANTECIPADO","DELEGOO","GUIMA","BOARO","OBS","⚙️"].map(h=>(
                        <th key={h} style={{padding:"10px 11px",textAlign:"left",color:"#64748b",fontWeight:600,fontSize:10,whiteSpace:"nowrap"}}>{h}</th>
                      ))}
                    </tr></thead>
                    <tbody>
                      {filtered.map((c,i)=>{
                        const r=calcC(c);
                        const s=SC2[c.status]||{bg:"#1a1d2e",tx:"#64748b",d:"#64748b"};
                        const t=TC2[c.tese]||{bg:"#1a1d2e",tx:"#94a3b8"};
                        const wa=waLink(c.telefone);
                        return(
                          <tr key={c.id} onClick={()=>setSelC(selC?.id===c.id?null:c)} style={{borderBottom:"1px solid #1e2a3a",cursor:"pointer",background:selC?.id===c.id?"#1e2a3a":i%2===0?"transparent":"#171a28"}}>
                            <td style={{padding:"9px 11px"}}><span style={{background:t.bg,color:t.tx,borderRadius:5,padding:"2px 6px",fontSize:10,fontWeight:700}}>{c.tese}</span></td>
                            <td style={{padding:"9px 11px"}}><span style={{background:s.bg,color:s.tx,borderRadius:20,padding:"3px 8px",fontSize:10,fontWeight:600,display:"inline-flex",alignItems:"center",gap:4,whiteSpace:"nowrap"}}><span style={{width:5,height:5,borderRadius:"50%",background:s.d}}/>{c.status}</span></td>
                            <td style={{padding:"9px 11px",fontWeight:700,color:"#f1f5f9",maxWidth:160}}>
                              <div style={{overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{c.nome}</div>
                              {c.telefone&&wa&&<a href={wa} target="_blank" rel="noopener noreferrer" onClick={e=>e.stopPropagation()} style={{display:"inline-flex",alignItems:"center",gap:3,color:"#34d399",fontSize:10,textDecoration:"none",marginTop:2}}><WAICO/>{c.telefone}</a>}
                            </td>
                            <td style={{padding:"9px 11px",color:"#94a3b8",whiteSpace:"nowrap"}}>{c.cidade}{c.uf?` / ${c.uf}`:""}</td>
                            <td style={{padding:"9px 11px",maxWidth:140}}>
                              <div style={{fontSize:11,color:"#64748b",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{c.processo||"—"}</div>
                              {c.fase&&<div style={{fontSize:10,color:"#4a5568",marginTop:2}}>{c.fase}</div>}
                            </td>
                            <td style={{padding:"9px 11px",maxWidth:130}}>
                              {c.temP1&&c.nomeP1&&<div style={{fontSize:10,color:"#818cf8",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>P1: {c.nomeP1} ({p100(c.p1Hon)})</div>}
                              {c.temP2&&c.nomeP2&&<div style={{fontSize:10,color:"#a78bfa",marginTop:2}}>P2: {c.nomeP2} ({p100(c.p2Hon)})</div>}
                            </td>
                            <td style={{padding:"9px 11px",color:"#94a3b8",whiteSpace:"nowrap"}}>{fmt(c.valorAcao)}</td>
                            <td style={{padding:"9px 11px",color:"#10b981",fontWeight:700,whiteSpace:"nowrap"}}>{fmt(r.antiGm+r.antiBo)}</td>
                            <td style={{padding:"9px 11px",color:"#6366f1",fontWeight:700,whiteSpace:"nowrap"}}>{fmt(r.honDel+r.sucDel)}</td>
                            <td style={{padding:"9px 11px",color:"#22d3ee",whiteSpace:"nowrap"}}>{fmt(r.honGm+r.sucGm)}</td>
                            <td style={{padding:"9px 11px",color:"#f59e0b",whiteSpace:"nowrap"}}>{fmt(r.honBo+r.sucBo)}</td>
                            <td style={{padding:"9px 11px",maxWidth:110}}>{c.obs&&<span title={c.obs} style={{background:"#1e2a3a",color:"#f59e0b",borderRadius:4,padding:"2px 6px",fontSize:10,display:"block",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{c.obs}</span>}</td>
                            <td style={{padding:"9px 11px"}}>
                              <div style={{display:"flex",gap:4}}>
                                <button onClick={e=>{e.stopPropagation();openEditC(c);}} style={{background:"#1e3a5f",color:"#60a5fa",border:"none",borderRadius:6,padding:"5px 8px",cursor:"pointer",fontSize:11}}>✏️</button>
                                <button onClick={e=>{e.stopPropagation();delC(c.id);}} style={{background:"#3f1d1d",color:"#f87171",border:"none",borderRadius:6,padding:"5px 8px",cursor:"pointer",fontSize:11}}>🗑️</button>
                              </div>
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                  {filtered.length===0&&<div style={{padding:32,textAlign:"center",color:"#4a5568"}}>Nenhum cliente encontrado</div>}
                </div>
              </div>
            </div>

            {/* Painel lateral cliente */}
            {selC&&(
              <div style={{width:310,flexShrink:0}}>
                <div style={{background:"#1a1d2e",borderRadius:14,border:"1px solid #2d3748",position:"sticky",top:14,overflow:"hidden"}}>
                  <div style={{background:"linear-gradient(135deg,#1e1b4b,#312e81)",padding:16}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
                      <div style={{flex:1,minWidth:0,paddingRight:8}}>
                        <div style={{fontSize:10,color:"#818cf8",fontWeight:700,letterSpacing:1,marginBottom:4}}>{selC.tese}</div>
                        <div style={{fontWeight:800,fontSize:13,color:"#f1f5f9",lineHeight:1.3,marginBottom:5,wordBreak:"break-word"}}>{selC.nome}</div>
                        {selC.cpf&&<div style={{fontSize:11,color:"#94a3b8",marginBottom:2}}>📄 {selC.cpf}</div>}
                        {selC.dataNasc&&<div style={{fontSize:11,color:"#94a3b8",marginBottom:2}}>🎂 {selC.dataNasc.split("-").reverse().join("/")}</div>}
                        {selC.email&&<div style={{fontSize:11,color:"#94a3b8",marginBottom:2}}>✉️ {selC.email}</div>}
                        <div style={{fontSize:11,color:"#94a3b8"}}>{selC.cidade}{selC.uf?` · ${selC.uf}`:""}</div>
                        {selC.endereco&&<div style={{fontSize:10,color:"#64748b",marginTop:2}}>{selC.endereco}</div>}
                        {selC.telefone&&waLink(selC.telefone)&&(
                          <a href={waLink(selC.telefone)} target="_blank" rel="noopener noreferrer" style={{display:"inline-flex",alignItems:"center",gap:5,background:"#064e3b",color:"#34d399",borderRadius:7,padding:"6px 10px",fontWeight:700,fontSize:11,textDecoration:"none",marginTop:8}}><WAICO/>WhatsApp</a>
                        )}
                      </div>
                      <button onClick={()=>setSelC(null)} style={{background:"#2d2d5e",border:"none",color:"#94a3b8",borderRadius:8,width:26,height:26,cursor:"pointer",fontSize:13,flexShrink:0}}>✕</button>
                    </div>
                  </div>
                  <div style={{padding:14,overflowY:"auto",maxHeight:"calc(100vh - 280px)"}}>
                    <div style={{marginBottom:10}}>
                      <Lbl ch="FASE DO PROCESSO"/>
                      <select value={selC.status} onChange={e=>updSt(selC.id,e.target.value)} style={{...sel,fontSize:12}}>{SL.map(s=><option key={s} value={s}>{s}</option>)}</select>
                    </div>
                    {(selC.processo||selC.comarca||selC.parteContraria)&&(
                      <div style={{background:"#0f1117",borderRadius:8,padding:"10px 12px",marginBottom:10}}>
                        <div style={{fontSize:10,color:"#64748b",fontWeight:700,marginBottom:6,textTransform:"uppercase"}}>Processo</div>
                        {selC.processo&&<div style={{fontSize:11,color:"#94a3b8",marginBottom:3}}>Nº {selC.processo}</div>}
                        {selC.fase&&<div style={{fontSize:11,color:"#818cf8",marginBottom:3}}>Fase: {selC.fase}</div>}
                        {selC.vara&&<div style={{fontSize:11,color:"#64748b",marginBottom:3}}>{selC.vara}</div>}
                        {selC.comarca&&<div style={{fontSize:11,color:"#64748b",marginBottom:3}}>Comarca: {selC.comarca}</div>}
                        {selC.parteContraria&&<div style={{fontSize:11,color:"#f87171"}}>Parte contrária: {selC.parteContraria}{selC.advPC?` (${selC.advPC})`:""}</div>}
                      </div>
                    )}
                    {(selC.temP1||selC.temP2)&&(
                      <div style={{background:"#0f1117",borderRadius:8,padding:"10px 12px",marginBottom:10}}>
                        <div style={{fontSize:10,color:"#64748b",fontWeight:700,marginBottom:6,textTransform:"uppercase"}}>Parceiros</div>
                        {selC.temP1&&selC.nomeP1&&<div style={{marginBottom:6}}><div style={{fontSize:11,color:"#818cf8",fontWeight:700}}>P1: {selC.nomeP1}</div><div style={{fontSize:10,color:"#64748b"}}>{selC.tipoP1} · Hon: {p100(selC.p1Hon)} · Suc: {p100(selC.p1Suc)}</div></div>}
                        {selC.temP2&&selC.nomeP2&&<div><div style={{fontSize:11,color:"#a78bfa",fontWeight:700}}>P2: {selC.nomeP2}</div><div style={{fontSize:10,color:"#64748b"}}>{selC.tipoP2} · Hon: {p100(selC.p2Hon)} · Suc: {p100(selC.p2Suc)}</div></div>}
                      </div>
                    )}
                    {selC.obs&&<div style={{background:"#1e2a3a",borderRadius:7,padding:"8px 10px",marginBottom:10,fontSize:11,color:"#f59e0b",borderLeft:"3px solid #f59e0b"}}>⚠️ {selC.obs}</div>}
                    {selR&&(
                      <div style={{background:"#0f1117",borderRadius:10,padding:12,marginBottom:10}}>
                        <div style={{fontSize:10,color:"#64748b",fontWeight:700,marginBottom:8,textTransform:"uppercase"}}>Resumo Financeiro</div>
                        <Row l="Valor da Ação" v={fmt(selC.valorAcao)}/>
                        <div style={{fontSize:10,color:"#10b981",fontWeight:700,margin:"6px 0 3px"}}>HONORÁRIOS ({p100(selC.pctHon)})</div>
                        <Row l="Total Hon." v={fmt(selR.honTot)}/>
                        <Row l={`✅ Antecipado (${p100(selC.pctAntec||0.15)})`} v={fmt(selR.antec)} c="#10b981" b/>
                        <Row l="  Delegoo antec." v={fmt(selR.antiGm+selR.antiBo)} c="#6366f1" sub={p100(selC.pctDelHon)}/>
                        {selC.temP1&&selC.nomeP1&&<Row l={`  ${selC.nomeP1}`} v={fmt(selR.honP1)} c="#818cf8" sub={p100(selC.p1Hon)}/>}
                        {selC.temP2&&selC.nomeP2&&<Row l={`  ${selC.nomeP2}`} v={fmt(selR.honP2)} c="#a78bfa" sub={p100(selC.p2Hon)}/>}
                        <Row l="  Delegoo" v={fmt(selR.honDel)} c="#6366f1" b sub={p100(selC.pctDelHon)}/>
                        <Row l="   Guima" v={fmt(selR.honGm)} c="#22d3ee"/>
                        <Row l="   Boaro" v={fmt(selR.honBo)} c="#f59e0b"/>
                        <div style={{fontSize:10,color:"#a78bfa",fontWeight:700,margin:"6px 0 3px"}}>SUCUMBÊNCIA ({p100(selC.pctSucumb)})</div>
                        <Row l="Total Sucumb." v={fmt(selR.sucTot)}/>
                        {selC.temP1&&selC.nomeP1&&<Row l={`  ${selC.nomeP1}`} v={fmt(selR.sucP1)} c="#818cf8" sub={p100(selC.p1Suc)}/>}
                        {selC.temP2&&selC.nomeP2&&<Row l={`  ${selC.nomeP2}`} v={fmt(selR.sucP2)} c="#a78bfa" sub={p100(selC.p2Suc)}/>}
                        <Row l="  Delegoo" v={fmt(selR.sucDel)} c="#6366f1" b sub={p100(selC.pctDelSuc)}/>
                        <Row l="   Guima" v={fmt(selR.sucGm)} c="#22d3ee"/>
                        <Row l="   Boaro" v={fmt(selR.sucBo)} c="#f59e0b"/>
                        <div style={{height:1,background:"#2d3748",margin:"8px 0"}}/>
                        <div style={{background:"linear-gradient(135deg,#0a1929,#0e2237)",borderRadius:8,padding:"10px 12px",border:"1px solid #1e3a5f"}}>
                          <div style={{fontSize:10,color:"#60a5fa",fontWeight:700,marginBottom:6}}>💰 TOTAL A RECEBER</div>
                          <Row l="Hon. restante" v={fmt(selR.rest)} c="#10b981"/>
                          <Row l="Sucumb. Delegoo" v={fmt(selR.sucDel)} c="#a78bfa"/>
                          <div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",marginTop:2}}>
                            <span style={{fontSize:12,color:"#60a5fa",fontWeight:700}}>TOTAL</span>
                            <span style={{fontSize:16,fontWeight:900,color:"#60a5fa"}}>{fmt(selR.rest+selR.sucDel)}</span>
                          </div>
                          <div style={{display:"flex",gap:6,marginTop:4}}>
                            <div style={{flex:1,background:"#0f1117",borderRadius:6,padding:"6px 8px",textAlign:"center"}}>
                              <div style={{fontSize:9,color:"#64748b"}}>Guima</div>
                              <div style={{fontSize:12,fontWeight:800,color:"#22d3ee"}}>{fmt((selR.rest+selR.sucDel)*(selC.pctGm||0.5))}</div>
                            </div>
                            <div style={{flex:1,background:"#0f1117",borderRadius:6,padding:"6px 8px",textAlign:"center"}}>
                              <div style={{fontSize:9,color:"#64748b"}}>Boaro</div>
                              <div style={{fontSize:12,fontWeight:800,color:"#f59e0b"}}>{fmt((selR.rest+selR.sucDel)*(selC.pctBo||0.5))}</div>
                            </div>
                          </div>
                        </div>
                      </div>
                    )}
                    {conn.cidade.length>0&&<div style={{background:"#0f1117",borderRadius:10,padding:12,marginBottom:8}}><div style={{fontSize:10,color:"#22d3ee",fontWeight:700,marginBottom:8}}>📍 MESMA CIDADE — {selC.cidade}</div>{conn.cidade.map(c=><div key={c.id} onClick={()=>setSelC(c)} style={{padding:"6px 0",borderBottom:"1px solid #1e2a3a",cursor:"pointer"}}><div style={{fontSize:12,color:"#f1f5f9",fontWeight:600}}>{c.nome}</div><div style={{fontSize:10,color:"#64748b"}}>{c.tese} · {c.status}</div></div>)}</div>}
                    {conn.sob.length>0&&<div style={{background:"#0f1117",borderRadius:10,padding:12,marginBottom:8}}><div style={{fontSize:10,color:"#f59e0b",fontWeight:700,marginBottom:8}}>👥 MESMO SOBRENOME — {sob(selC.nome)}</div>{conn.sob.map(c=><div key={c.id} onClick={()=>setSelC(c)} style={{padding:"6px 0",borderBottom:"1px solid #1e2a3a",cursor:"pointer"}}><div style={{fontSize:12,color:"#f1f5f9",fontWeight:600}}>{c.nome}</div><div style={{fontSize:10,color:"#64748b"}}>{c.cidade||"—"} · {c.status}</div></div>)}</div>}
                    <div style={{display:"flex",gap:8,marginTop:4}}>
                      <button onClick={()=>openEditC(selC)} style={{flex:1,background:"linear-gradient(135deg,#4f46e5,#7c3aed)",color:"#fff",border:"none",borderRadius:8,padding:10,fontWeight:700,fontSize:12,cursor:"pointer"}}>✏️ Editar</button>
                      <button onClick={()=>delC(selC.id)} style={{background:"#3f1d1d",color:"#f87171",border:"1px solid #7f1d1d",borderRadius:8,padding:"10px 12px",cursor:"pointer",fontSize:12}}>🗑️</button>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ══════════════════════════════════════════════════════════
          MÓDULO FINANCEIRO
      ══════════════════════════════════════════════════════════ */}
      {nav==="financeiro"&&(
        <div style={{maxWidth:1400,margin:"0 auto",padding:"14px 20px 32px"}}>
          {/* Navegação de mês */}
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16}}>
            <div style={{display:"flex",alignItems:"center",gap:8}}>
              <button onClick={()=>navMes(-1)} style={{background:"#1a1d2e",border:"1px solid #2d3748",color:"#94a3b8",borderRadius:8,width:32,height:32,cursor:"pointer",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center"}}>‹</button>
              <div style={{textAlign:"center",minWidth:130}}><div style={{fontWeight:800,fontSize:16,color:"#f1f5f9"}}>{MESES[mes]}</div><div style={{fontSize:11,color:"#64748b"}}>{ano}</div></div>
              <button onClick={()=>navMes(1)} style={{background:"#1a1d2e",border:"1px solid #2d3748",color:"#94a3b8",borderRadius:8,width:32,height:32,cursor:"pointer",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center"}}>›</button>
            </div>
            <div style={{display:"flex",gap:4}}>
              {[["resumo","📊 Resumo"],["lancamentos","📋 Lançamentos"],["historico","📈 Histórico"]].map(([v,l])=>(
                <button key={v} onClick={()=>setAbaFin(v)} style={{padding:"8px 14px",borderRadius:8,border:"none",cursor:"pointer",fontWeight:700,fontSize:12,background:abaFin===v?"linear-gradient(135deg,#10b981,#059669)":"#1a1d2e",color:abaFin===v?"#fff":"#64748b",border:abaFin===v?"none":"1px solid #2d3748"}}>{l}</button>
              ))}
            </div>
          </div>

          {/* Cards resumo financeiro */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:10,marginBottom:16}}>
            <Card label="Entradas" value={fmt(finTotais.ent)} color="#10b981" sub={`${doMes.filter(l=>isEnt(l.tipo)).length} lançamentos`}/>
            <Card label="Total Saídas" value={fmt(finTotais.sai)} color="#ef4444" sub={`${doMes.filter(l=>!isEnt(l.tipo)).length} lançamentos`}/>
            <Card label="Saldo do Mês" value={fmt(finTotais.saldo)} color={finTotais.saldo>=0?"#10b981":"#ef4444"} sub={finTotais.saldo>=0?"✅ Positivo":"⚠️ Negativo"}/>
            <Card label="Saída Guima" value={fmt(finTotais.sGm)} color="#22d3ee" sub="Fixas + Var. + ½ Empresa"/>
            <Card label="Saída Boaro" value={fmt(finTotais.sBo)} color="#f59e0b" sub="Fixas + Var. + ½ Empresa"/>
          </div>

          {/* ABA RESUMO */}
          {abaFin==="resumo"&&(
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
              {/* Entradas */}
              <div style={{background:"#1a1d2e",borderRadius:14,padding:18,border:"1px solid #2d3748"}}>
                <div style={{fontWeight:700,fontSize:13,color:"#10b981",marginBottom:14}}>↑ ENTRADAS — {fmt(finTotais.ent)}</div>
                {Object.values(doMes.filter(l=>isEnt(l.tipo)).reduce((acc,l)=>{const k=l.cat;if(!acc[k])acc[k]={cat:l.cat,tot:0};acc[k].tot+=l.valor||0;return acc;},{})).map(c=>(
                  <div key={c.cat} style={{marginBottom:10}}>
                    <div style={{display:"flex",justifyContent:"space-between",fontSize:12}}><span style={{color:"#e2e8f0"}}>{c.cat}</span><span style={{color:"#10b981",fontWeight:700}}>{fmt(c.tot)}</span></div>
                    <MiniBar pct={(c.tot/finTotais.ent)*100} color="#10b981"/>
                  </div>
                ))}
                {finTotais.ent===0&&<div style={{color:"#4a5568",fontSize:12}}>Nenhuma entrada lançada</div>}
              </div>
              {/* Saídas */}
              <div style={{background:"#1a1d2e",borderRadius:14,padding:18,border:"1px solid #2d3748"}}>
                <div style={{fontWeight:700,fontSize:13,color:"#ef4444",marginBottom:14}}>↓ SAÍDAS — {fmt(finTotais.sai)}</div>
                {[["🏢 Fixas Empresa",finTotais.fEmp,"#60a5fa"],["G Fixas Guima",finTotais.fGm,"#22d3ee"],["B Fixas Boaro",finTotais.fBo,"#f59e0b"],["🏢 Variáveis Empresa",finTotais.vEmp,"#a78bfa"],["G Variáveis Guima",finTotais.vGm,"#34d399"],["B Variáveis Boaro",finTotais.vBo,"#fbbf24"]].filter(([,v])=>v>0).map(([l,v,c])=>(
                  <div key={l} style={{marginBottom:10}}>
                    <div style={{display:"flex",justifyContent:"space-between",fontSize:12}}><span style={{color:"#e2e8f0"}}>{l}</span><span style={{color:c,fontWeight:700}}>{fmt(v)}</span></div>
                    <MiniBar pct={(v/finTotais.sai)*100} color={c}/>
                  </div>
                ))}
                {finTotais.sai===0&&<div style={{color:"#4a5568",fontSize:12}}>Nenhuma saída lançada</div>}
              </div>
              {/* Resumo por sócio */}
              {[["GUIMA","#22d3ee",finTotais.fGm,finTotais.vGm,finTotais.fEmp/2,finTotais.vEmp/2],["BOARO","#f59e0b",finTotais.fBo,finTotais.vBo,finTotais.fEmp/2,finTotais.vEmp/2]].map(([nm,cl,fP,vP,fE,vE])=>(
                <div key={nm} style={{background:"#1a1d2e",borderRadius:14,padding:18,border:"1px solid #2d3748"}}>
                  <div style={{fontWeight:700,fontSize:13,color:cl,marginBottom:14}}>👤 RESUMO {nm}</div>
                  <Row l="Fixas Pessoais" v={fmt(fP)} c={cl}/>
                  <Row l="Variáveis Pessoais" v={fmt(vP)} c={cl}/>
                  <Row l="½ Fixas Empresa" v={fmt(fE)} c="#64748b"/>
                  <Row l="½ Variáveis Empresa" v={fmt(vE)} c="#64748b"/>
                  <div style={{height:1,background:"#2d3748",margin:"8px 0"}}/>
                  <Row l="Total Saídas" v={fmt(fP+vP+fE+vE)} c={cl} b/>
                  <Row l="½ Entradas Mês" v={fmt(finTotais.ent/2)} c="#10b981"/>
                  <div style={{height:1,background:"#2d3748",margin:"8px 0"}}/>
                  <Row l="Saldo Estimado" v={fmt(finTotais.ent/2-(fP+vP+fE+vE))} c={finTotais.ent/2-(fP+vP+fE+vE)>=0?"#10b981":"#ef4444"} b/>
                </div>
              ))}
            </div>
          )}

          {/* ABA LANÇAMENTOS */}
          {abaFin==="lancamentos"&&(
            <div>
              <div style={{display:"flex",gap:6,marginBottom:12,flexWrap:"wrap"}}>
                {[["todos","Todos"],...Object.entries(TIPO_FIN_LABELS).map(([k,v])=>[k,v.label])].map(([k,l])=>(
                  <button key={k} onClick={()=>setFTipo(k)} style={{padding:"6px 12px",borderRadius:8,border:"2px solid",borderColor:fTipo===k?(TIPO_FIN_LABELS[k]?.color||"#6366f1"):"#2d3748",background:fTipo===k?"#1e2a3a":"transparent",color:fTipo===k?(TIPO_FIN_LABELS[k]?.color||"#e2e8f0"):"#64748b",fontWeight:700,cursor:"pointer",fontSize:11}}>{l}</button>
                ))}
              </div>
              <div style={{background:"#1a1d2e",borderRadius:14,border:"1px solid #2d3748",overflow:"hidden"}}>
                <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                  <thead><tr style={{background:"#16213e",borderBottom:"1px solid #2d3748"}}>
                    {["DATA","TIPO","CATEGORIA","DESCRIÇÃO","VALOR",""].map(h=><th key={h} style={{padding:"10px 14px",textAlign:"left",color:"#64748b",fontWeight:600,fontSize:10,whiteSpace:"nowrap"}}>{h}</th>)}
                  </tr></thead>
                  <tbody>
                    {filtLancs.sort((a,b)=>(b.data||"").localeCompare(a.data||"")).map((l,i)=>(
                      <tr key={l.id} style={{borderBottom:"1px solid #1e2a3a",background:i%2===0?"transparent":"#171a28"}}>
                        <td style={{padding:"10px 14px",color:"#64748b",whiteSpace:"nowrap"}}>{l.data?l.data.split("-").reverse().join("/"):"—"}</td>
                        <td style={{padding:"10px 14px"}}><Badge tipo={l.tipo}/></td>
                        <td style={{padding:"10px 14px",color:"#94a3b8"}}>{l.cat}</td>
                        <td style={{padding:"10px 14px",color:"#f1f5f9",fontWeight:600}}>{l.desc}</td>
                        <td style={{padding:"10px 14px",fontWeight:800,color:isEnt(l.tipo)?"#10b981":"#ef4444",whiteSpace:"nowrap"}}>{isEnt(l.tipo)?"+":"-"}{fmt(l.valor)}</td>
                        <td style={{padding:"10px 14px"}}>
                          <div style={{display:"flex",gap:6}}>
                            <button onClick={()=>openEditL(l)} style={{background:"#1e3a5f",color:"#60a5fa",border:"none",borderRadius:6,padding:"5px 8px",cursor:"pointer",fontSize:11}}>✏️</button>
                            <button onClick={()=>delL(l.id)} style={{background:"#3f1d1d",color:"#f87171",border:"none",borderRadius:6,padding:"5px 8px",cursor:"pointer",fontSize:11}}>🗑️</button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
                {filtLancs.length===0&&<div style={{padding:32,textAlign:"center",color:"#4a5568"}}>Nenhum lançamento neste mês</div>}
              </div>
            </div>
          )}

          {/* ABA HISTÓRICO */}
          {abaFin==="historico"&&(
            <div>
              <div style={{background:"#1a1d2e",borderRadius:14,padding:20,border:"1px solid #2d3748",marginBottom:14}}>
                <div style={{fontWeight:700,fontSize:13,color:"#94a3b8",marginBottom:20}}>ÚLTIMOS 6 MESES</div>
                <div style={{display:"flex",alignItems:"flex-end",gap:12,height:160}}>
                  {hist.map(h=>(
                    <div key={`${h.mes}-${h.ano}`} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
                      <div style={{width:"100%",display:"flex",gap:3,alignItems:"flex-end",height:130}}>
                        <div style={{flex:1,background:"#10b981",borderRadius:"3px 3px 0 0",height:`${(h.e/maxH)*100}%`,minHeight:h.e>0?4:0}} title={fmt(h.e)}/>
                        <div style={{flex:1,background:"#ef4444",borderRadius:"3px 3px 0 0",height:`${(h.s/maxH)*100}%`,minHeight:h.s>0?4:0}} title={fmt(h.s)}/>
                      </div>
                      <div style={{fontSize:10,color:"#64748b",fontWeight:600}}>{h.label}</div>
                      <div style={{fontSize:10,color:h.saldo>=0?"#10b981":"#ef4444",fontWeight:700}}>{h.saldo>=0?"+":""}{fmt(h.saldo).replace("R$ ","")}</div>
                    </div>
                  ))}
                </div>
                <div style={{display:"flex",gap:16,marginTop:12}}>
                  <div style={{display:"flex",alignItems:"center",gap:6}}><div style={{width:10,height:10,borderRadius:2,background:"#10b981"}}/><span style={{fontSize:11,color:"#64748b"}}>Entradas</span></div>
                  <div style={{display:"flex",alignItems:"center",gap:6}}><div style={{width:10,height:10,borderRadius:2,background:"#ef4444"}}/><span style={{fontSize:11,color:"#64748b"}}>Saídas</span></div>
                </div>
              </div>
              <div style={{background:"#1a1d2e",borderRadius:14,border:"1px solid #2d3748",overflow:"hidden"}}>
                <table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
                  <thead><tr style={{background:"#16213e",borderBottom:"1px solid #2d3748"}}>
                    {["Mês","Entradas","Saídas","Saldo","Lançamentos"].map(h=><th key={h} style={{padding:"10px 14px",textAlign:"left",color:"#64748b",fontWeight:600,fontSize:10}}>{h.toUpperCase()}</th>)}
                  </tr></thead>
                  <tbody>
                    {[...hist].reverse().map((h,i)=>(
                      <tr key={`${h.mes}-${h.ano}`} onClick={()=>{setMes(h.mes);setAno(h.ano);setAbaFin("lancamentos");}} style={{borderBottom:"1px solid #1e2a3a",cursor:"pointer",background:h.mes===mes&&h.ano===ano?"#1e2a3a":i%2===0?"transparent":"#171a28"}}>
                        <td style={{padding:"10px 14px",color:"#f1f5f9",fontWeight:700}}>{MESES[h.mes]} {h.ano}</td>
                        <td style={{padding:"10px 14px",color:"#10b981",fontWeight:700}}>{fmt(h.e)}</td>
                        <td style={{padding:"10px 14px",color:"#ef4444",fontWeight:700}}>{fmt(h.s)}</td>
                        <td style={{padding:"10px 14px",color:h.saldo>=0?"#10b981":"#ef4444",fontWeight:800}}>{h.saldo>=0?"+":""}{fmt(h.saldo)}</td>
                        <td style={{padding:"10px 14px",color:"#64748b"}}>{lancs.filter(l=>l.mes===h.mes&&l.ano===h.ano).length}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      )}

      {/* ══════════════════════════════════════════════════════════
          DASHBOARD
      ══════════════════════════════════════════════════════════ */}
      {nav==="dashboard"&&(
        <div style={{maxWidth:1400,margin:"0 auto",padding:"14px 20px 32px"}}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
            <Card label="Clientes Ativos" value={clients.filter(c=>!["FECHADO"].includes(c.status)).length} color="#6366f1" sub="Em andamento"/>
            <Card label="Clientes Fechados" value={clients.filter(c=>c.status==="FECHADO").length} color="#10b981"/>
            <Card label="Entradas (mês atual)" value={fmt(finTotais.ent)} color="#10b981"/>
            <Card label="Saldo Mês Atual" value={fmt(finTotais.saldo)} color={finTotais.saldo>=0?"#10b981":"#ef4444"}/>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
            {/* Por tese */}
            <div style={{background:"#1a1d2e",borderRadius:14,padding:18,border:"1px solid #2d3748"}}>
              <div style={{fontWeight:700,fontSize:13,color:"#94a3b8",marginBottom:14}}>CLIENTES POR TESE</div>
              {TL.map(t=>{const n=clients.filter(c=>c.tese===t).length;if(!n)return null;const tc=TC2[t]||{};return(<div key={t} style={{marginBottom:10}}><div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:4}}><span style={{color:tc.tx||"#94a3b8",fontWeight:600}}>{t}</span><span style={{color:"#e2e8f0",fontWeight:700}}>{n} clientes</span></div><MiniBar pct={(n/clients.length)*100} color={tc.tx||"#6366f1"}/></div>);})}
            </div>
            {/* Por status */}
            <div style={{background:"#1a1d2e",borderRadius:14,padding:18,border:"1px solid #2d3748"}}>
              <div style={{fontWeight:700,fontSize:13,color:"#94a3b8",marginBottom:14}}>CLIENTES POR STATUS</div>
              {SL.filter(s=>clients.some(c=>c.status===s)).map(s=>{const n=clients.filter(c=>c.status===s).length;const sc=SC2[s]||{};return(<div key={s} style={{marginBottom:8}}><div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:3}}><span style={{color:sc.tx||"#94a3b8",fontSize:11}}>{s}</span><span style={{color:"#e2e8f0",fontWeight:700}}>{n}</span></div><MiniBar pct={(n/clients.length)*100} color={sc.d||"#64748b"}/></div>);})}
            </div>
            {/* Saídas mensais */}
            <div style={{background:"#1a1d2e",borderRadius:14,padding:18,border:"1px solid #2d3748"}}>
              <div style={{fontWeight:700,fontSize:13,color:"#94a3b8",marginBottom:14}}>SAÍDAS {MESES[mes].toUpperCase()} POR GRUPO</div>
              {[["Fixas Empresa",finTotais.fEmp,"#60a5fa"],["Fixas Guima",finTotais.fGm,"#22d3ee"],["Fixas Boaro",finTotais.fBo,"#f59e0b"],["Variáveis Empresa",finTotais.vEmp,"#a78bfa"],["Variáveis Guima",finTotais.vGm,"#34d399"],["Variáveis Boaro",finTotais.vBo,"#fbbf24"]].filter(([,v])=>v>0).map(([l,v,c])=>(
                <div key={l} style={{marginBottom:9}}><div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:3}}><span style={{color:"#94a3b8"}}>{l}</span><span style={{color:c,fontWeight:700}}>{fmt(v)}</span></div><MiniBar pct={finTotais.sai>0?(v/finTotais.sai)*100:0} color={c}/></div>
              ))}
              {finTotais.sai===0&&<div style={{color:"#4a5568",fontSize:12}}>Sem saídas lançadas</div>}
            </div>
            {/* CRM Projeção */}
            <div style={{background:"#1a1d2e",borderRadius:14,padding:18,border:"1px solid #2d3748"}}>
              <div style={{fontWeight:700,fontSize:13,color:"#94a3b8",marginBottom:14}}>PROJEÇÃO CRM</div>
              {(()=>{let tH=0,tS=0,tD=0,tG=0,tB=0;clients.forEach(c=>{const r=calcC(c);tH+=r.honTot;tS+=r.sucTot;tD+=r.honDel+r.sucDel;tG+=r.honGm+r.sucGm;tB+=r.honBo+r.sucBo;});return(<><Row l="Total Honorários (todos)" v={fmt(tH)}/><Row l="Total Sucumbência" v={fmt(tS)}/><div style={{height:1,background:"#2d3748",margin:"8px 0"}}/><Row l="Delegoo Total" v={fmt(tD)} c="#6366f1" b/><Row l="Guima Total" v={fmt(tG)} c="#22d3ee" b/><Row l="Boaro Total" v={fmt(tB)} c="#f59e0b" b/></>);})()}
            </div>
          </div>
        </div>
      )}

      {/* ══════════════════════════════════════════════════════════
          MODAL CLIENTE
      ══════════════════════════════════════════════════════════ */}
      {showFC&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.85)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,padding:16}}>
          <div style={{background:"#1a1d2e",borderRadius:16,border:"1px solid #2d3748",width:"100%",maxWidth:720,maxHeight:"93vh",overflowY:"auto"}}>
            <div style={{padding:"14px 20px",borderBottom:"1px solid #2d3748",display:"flex",justifyContent:"space-between",alignItems:"center",position:"sticky",top:0,background:"#1a1d2e",zIndex:1}}>
              <div style={{fontWeight:800,fontSize:15,color:"#f1f5f9"}}>{editC?"✏️ Editar Cliente":"➕ Novo Cliente"}</div>
              <button onClick={()=>setShowFC(false)} style={{background:"#2d3748",border:"none",color:"#94a3b8",borderRadius:8,width:30,height:30,cursor:"pointer",fontSize:16}}>✕</button>
            </div>
            <div style={{display:"flex",gap:4,padding:"12px 20px 0",borderBottom:"1px solid #2d3748"}}>
              {[["cliente","👤 Cliente"],["processo","⚖️ Processo"],["financeiro","💰 Financeiro"]].map(([v,l])=>(
                <button key={v} onClick={()=>setAbaFC(v)} style={{padding:"8px 16px",borderRadius:"8px 8px 0 0",border:"none",cursor:"pointer",fontWeight:700,fontSize:12,background:abaFC===v?"#0f1117":"transparent",color:abaFC===v?"#818cf8":"#64748b",borderBottom:abaFC===v?"2px solid #6366f1":"2px solid transparent"}}>{l}</button>
              ))}
            </div>
            <div style={{padding:20}}>
              {/* ABA CLIENTE */}
              {abaFC==="cliente"&&(
                <div>
                  <div style={{display:"grid",gridTemplateColumns:"auto 1fr",gap:12,marginBottom:12}}>
                    <div><Lbl ch="TESE"/><div style={{display:"flex",gap:5,flexWrap:"wrap"}}>{TL.map(t=><button key={t} onClick={()=>sc("tese",t)} style={{padding:"6px 9px",borderRadius:7,border:"2px solid",borderColor:formC.tese===t?"#6366f1":"#2d3748",background:formC.tese===t?"#1e1b4b":"transparent",color:formC.tese===t?"#818cf8":"#64748b",fontWeight:700,cursor:"pointer",fontSize:11}}>{t}</button>)}</div></div>
                    <div><Lbl ch="STATUS"/><select value={formC.status} onChange={e=>sc("status",e.target.value)} style={sel}>{SL.map(s=><option key={s} value={s}>{s}</option>)}</select></div>
                  </div>
                  <div style={{marginBottom:12}}><Lbl ch="NOME COMPLETO"/><input value={formC.nome} onChange={e=>sc("nome",e.target.value)} placeholder="Nome completo" style={inp}/></div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:12}}>
                    <div><Lbl ch="CPF / CNPJ"/><input value={formC.cpf} onChange={e=>sc("cpf",e.target.value)} placeholder="000.000.000-00" style={inp}/></div>
                    <div><Lbl ch="DATA NASCIMENTO"/><input type="date" value={formC.dataNasc} onChange={e=>sc("dataNasc",e.target.value)} style={inp}/></div>
                  </div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:12}}>
                    <div><Lbl ch="TELEFONE / WHATSAPP"/>
                      <input value={formC.telefone} onChange={e=>sc("telefone",e.target.value)} placeholder="(51) 99999-9999" style={inp}/>
                      {formC.telefone&&waLink(formC.telefone)&&<a href={waLink(formC.telefone)} target="_blank" rel="noopener noreferrer" style={{display:"flex",alignItems:"center",gap:4,marginTop:4,color:"#34d399",fontSize:11,textDecoration:"none",fontWeight:600}}><WAICO/>Testar WhatsApp ↗</a>}
                    </div>
                    <div><Lbl ch="E-MAIL"/><input value={formC.email} onChange={e=>sc("email",e.target.value)} placeholder="email@exemplo.com" style={inp}/></div>
                  </div>
                  <div style={{marginBottom:12}}><Lbl ch="ENDEREÇO"/><input value={formC.endereco} onChange={e=>sc("endereco",e.target.value)} placeholder="Rua, número, bairro" style={inp}/></div>
                  <div style={{display:"grid",gridTemplateColumns:"2fr 1fr",gap:12,marginBottom:12}}>
                    <div><Lbl ch="CIDADE"/><input value={formC.cidade} onChange={e=>sc("cidade",e.target.value)} placeholder="Cidade" style={inp}/></div>
                    <div><Lbl ch="UF"/><select value={formC.uf} onChange={e=>sc("uf",e.target.value)} style={sel}><option value="">—</option>{UFL.map(u=><option key={u} value={u}>{u}</option>)}</select></div>
                  </div>
                  <div><Lbl ch="OBSERVAÇÕES"/><input value={formC.obs} onChange={e=>sc("obs",e.target.value)} placeholder="Ex: Passou GILRAT, Cobrar cumprimento..." style={inp}/></div>
                </div>
              )}
              {/* ABA PROCESSO */}
              {abaFC==="processo"&&(
                <div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:12}}>
                    <div><Lbl ch="Nº DO PROCESSO"/><input value={formC.processo} onChange={e=>sc("processo",e.target.value)} placeholder="0000000-00.0000.0.00.0000" style={inp}/></div>
                    <div><Lbl ch="FASE PROCESSUAL"/><select value={formC.fase} onChange={e=>sc("fase",e.target.value)} style={sel}>{FASES.map(f=><option key={f} value={f}>{f}</option>)}</select></div>
                  </div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:12}}>
                    <div><Lbl ch="VARA / JUÍZO"/><input value={formC.vara} onChange={e=>sc("vara",e.target.value)} placeholder="Ex: 1ª Vara Federal" style={inp}/></div>
                    <div><Lbl ch="COMARCA"/><input value={formC.comarca} onChange={e=>sc("comarca",e.target.value)} placeholder="Cidade da comarca" style={inp}/></div>
                  </div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:16}}>
                    <div><Lbl ch="PARTE CONTRÁRIA"/><input value={formC.parteContraria} onChange={e=>sc("parteContraria",e.target.value)} placeholder="Ex: INSS, União Federal" style={inp}/></div>
                    <div><Lbl ch="ADV. PARTE CONTRÁRIA"/><input value={formC.advPC} onChange={e=>sc("advPC",e.target.value)} placeholder="Ex: AGU" style={inp}/></div>
                  </div>
                  {/* Parceiro 1 */}
                  <div style={{background:"#0f1117",borderRadius:10,padding:14,marginBottom:12,border:"1px solid #2d3748"}}>
                    <div style={{marginBottom:formC.temP1?12:0}}><Toggle on={formC.temP1} onToggle={()=>sc("temP1",!formC.temP1)} label="Parceiro 1 (ex: Escritório Jurídico)" color="#6366f1"/></div>
                    {formC.temP1&&(
                      <div>
                        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:10}}>
                          <div><Lbl ch="NOME"/><input value={formC.nomeP1} onChange={e=>sc("nomeP1",e.target.value)} placeholder="Nome do parceiro" style={inp}/></div>
                          <div><Lbl ch="TIPO"/><select value={formC.tipoP1} onChange={e=>sc("tipoP1",e.target.value)} style={sel}>{TIPO_PARC.map(t=><option key={t} value={t}>{t}</option>)}</select></div>
                        </div>
                        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                          <Pct label="% P1 Honorários" value={formC.p1Hon} onChange={v=>setPH("p1Hon",v)} color="#818cf8" baseVal={(formC.valorAcao||0)*(formC.pctHon||0)}/>
                          <Pct label="% P1 Sucumbência" value={formC.p1Suc} onChange={v=>setPS("p1Suc",v)} color="#818cf8" baseVal={(formC.valorAcao||0)*(formC.pctSucumb||0)}/>
                        </div>
                      </div>
                    )}
                  </div>
                  {/* Parceiro 2 */}
                  <div style={{background:"#0f1117",borderRadius:10,padding:14,border:"1px solid #2d3748"}}>
                    <div style={{marginBottom:formC.temP2?12:0}}><Toggle on={formC.temP2} onToggle={()=>sc("temP2",!formC.temP2)} label="Parceiro 2 (ex: Contabilidade, Advogado)" color="#a78bfa"/></div>
                    {formC.temP2&&(
                      <div>
                        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:10}}>
                          <div><Lbl ch="NOME"/><input value={formC.nomeP2} onChange={e=>sc("nomeP2",e.target.value)} placeholder="Nome do parceiro 2" style={inp}/></div>
                          <div><Lbl ch="TIPO"/><select value={formC.tipoP2} onChange={e=>sc("tipoP2",e.target.value)} style={sel}>{TIPO_PARC.map(t=><option key={t} value={t}>{t}</option>)}</select></div>
                        </div>
                        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                          <Pct label="% P2 Honorários" value={formC.p2Hon} onChange={v=>setPH("p2Hon",v)} color="#a78bfa" baseVal={(formC.valorAcao||0)*(formC.pctHon||0)}/>
                          <Pct label="% P2 Sucumbência" value={formC.p2Suc} onChange={v=>setPS("p2Suc",v)} color="#a78bfa" baseVal={(formC.valorAcao||0)*(formC.pctSucumb||0)}/>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              )}
              {/* ABA FINANCEIRO */}
              {abaFC==="financeiro"&&(
                <div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:14}}>
                    <div><Lbl ch="VALOR DA AÇÃO (R$)"/><input type="number" value={formC.valorAcao||""} onChange={e=>sc("valorAcao",parseFloat(e.target.value)||0)} style={inp}/></div>
                    <div><Lbl ch="VALOR SEM GILRAT (R$)"/><input type="number" value={formC.semGilrat||""} onChange={e=>sc("semGilrat",parseFloat(e.target.value)||0)} style={inp}/></div>
                  </div>
                  <div style={{background:"#0f1117",borderRadius:10,padding:14,marginBottom:12}}>
                    <div style={{fontSize:11,color:"#10b981",fontWeight:700,marginBottom:10}}>HONORÁRIOS CONTRATUAIS</div>
                    <Pct label="% Honorários Contratuais" value={formC.pctHon} onChange={v=>sc("pctHon",v)} color="#10b981" baseVal={formC.valorAcao||0}/>

                    {/* ANTECIPADO - valor fixo OU percentual */}
                    <div style={{background:"#0a2e1a",borderRadius:8,padding:12,marginBottom:10,border:"1px solid #064e3b"}}>
                      <div style={{fontSize:11,color:"#34d399",fontWeight:700,marginBottom:8}}>✅ ANTECIPADO JÁ RECEBIDO</div>
                      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:8}}>
                        <div>
                          <div style={{fontSize:10,color:"#64748b",marginBottom:4}}>VALOR FIXO RECEBIDO (R$)</div>
                          <input
                            type="number"
                            value={formC.valorAntecipado||""}
                            onChange={e=>sc("valorAntecipado",parseFloat(e.target.value)||0)}
                            placeholder="Ex: 579,26"
                            style={{width:"100%",background:"#0f1117",border:"1px solid #10b981",borderRadius:7,padding:"9px 12px",color:"#34d399",fontSize:14,fontWeight:700,outline:"none",boxSizing:"border-box"}}
                          />
                          <div style={{fontSize:10,color:"#64748b",marginTop:3}}>Digite o valor exato recebido</div>
                        </div>
                        <div>
                          <div style={{fontSize:10,color:"#64748b",marginBottom:4}}>OU % DO HON. CONTRATUAL</div>
                          <div style={{display:"flex",alignItems:"center",gap:6}}>
                            <input type="number" min={0} max={100} step={1}
                              value={Math.round((formC.pctAntec||0.15)*100)}
                              onChange={e=>{sc("pctAntec",(parseInt(e.target.value)||0)/100);sc("valorAntecipado",0);}}
                              style={{width:"100%",background:"#0f1117",border:"1px solid #2d3748",borderRadius:7,padding:"9px 10px",color:"#34d399",fontSize:14,fontWeight:700,outline:"none",textAlign:"center"}}
                            />
                            <span style={{color:"#34d399",fontWeight:800}}>%</span>
                          </div>
                          <div style={{fontSize:10,color:"#64748b",marginTop:3}}>
                            = {fmt((formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctAntec||0.15))}
                          </div>
                        </div>
                      </div>
                      <div style={{background:"#0f1117",borderRadius:6,padding:"8px 12px",display:"flex",justifyContent:"space-between"}}>
                        <span style={{fontSize:12,color:"#64748b"}}>Antecipado considerado:</span>
                        <span style={{fontSize:14,fontWeight:800,color:"#34d399"}}>
                          {fmt(formC.valorAntecipado>0 ? formC.valorAntecipado : (formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctAntec||0.15))}
                        </span>
                      </div>
                    </div>

                    {/* RESTANTE A RECEBER */}
                    <div style={{background:"#0a1929",borderRadius:8,padding:12,marginBottom:10,border:"1px solid #1e3a5f"}}>
                      <div style={{fontSize:11,color:"#60a5fa",fontWeight:700,marginBottom:8}}>🏁 RESTANTE A RECEBER (sobre honorários atualizados)</div>
                      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:8}}>
                        <div>
                          <div style={{fontSize:10,color:"#64748b",marginBottom:4}}>% AINDA A RECEBER</div>
                          <div style={{display:"flex",alignItems:"center",gap:6}}>
                            <input type="number" min={0} max={100} step={1}
                              value={Math.round((formC.pctRestante||0.18)*100)}
                              onChange={e=>sc("pctRestante",(parseInt(e.target.value)||0)/100)}
                              style={{width:"100%",background:"#0f1117",border:"1px solid #1e3a5f",borderRadius:7,padding:"9px 10px",color:"#60a5fa",fontSize:14,fontWeight:700,outline:"none",textAlign:"center"}}
                            />
                            <span style={{color:"#60a5fa",fontWeight:800}}>%</span>
                          </div>
                        </div>
                        <div>
                          <div style={{fontSize:10,color:"#64748b",marginBottom:4}}>VALOR A RECEBER</div>
                          <div style={{background:"#0f1117",border:"1px solid #1e3a5f",borderRadius:7,padding:"9px 12px",color:"#60a5fa",fontSize:14,fontWeight:800,textAlign:"right"}}>
                            {fmt((formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctRestante||0.18))}
                          </div>
                          <div style={{fontSize:10,color:"#64748b",marginTop:3}}>
                            {p100(formC.pctRestante||0.18)} × {fmt((formC.valorAcao||0)*(formC.pctHon||0))}
                          </div>
                        </div>
                      </div>
                      <div style={{background:"#0f1117",borderRadius:6,padding:"8px 12px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                        <span style={{fontSize:11,color:"#64748b"}}>Total honorários (antecipado + restante):</span>
                        <span style={{fontSize:13,fontWeight:800,color:"#e2e8f0"}}>
                          {fmt((formC.valorAntecipado>0?formC.valorAntecipado:(formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctAntec||0.15)) + (formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctRestante||0.18))}
                        </span>
                      </div>
                    </div>

                    <div style={{height:1,background:"#2d3748",margin:"8px 0"}}/>
                    <div style={{fontSize:11,color:"#64748b",marginBottom:8}}>Divisão do restante a receber (Delegoo)</div>
                    {formC.temP1&&<Pct label={`% ${formC.nomeP1||"Parceiro 1"}`} value={formC.p1Hon} onChange={v=>setPH("p1Hon",v)} color="#818cf8" baseVal={(formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctRestante||0.18)}/>}
                    {formC.temP2&&<Pct label={`% ${formC.nomeP2||"Parceiro 2"}`} value={formC.p2Hon} onChange={v=>setPH("p2Hon",v)} color="#a78bfa" baseVal={(formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctRestante||0.18)}/>}
                    <Pct label="% Delegoo" value={formC.pctDelHon} onChange={v=>setPH("pctDelHon",v)} color="#6366f1" baseVal={(formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctRestante||0.18)}/>
                    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
                      <Pct label="% Guima" value={formC.pctGm} onChange={v=>{sc("pctGm",v);sc("pctBo",Math.round((1-v)*100)/100);}} color="#22d3ee" baseVal={(formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctRestante||0.18)*(formC.pctDelHon||0)}/>
                      <Pct label="% Boaro" value={formC.pctBo} onChange={v=>{sc("pctBo",v);sc("pctGm",Math.round((1-v)*100)/100);}} color="#f59e0b" baseVal={(formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctRestante||0.18)*(formC.pctDelHon||0)}/>
                    </div>
                  </div>
                  <div style={{background:"#0f1117",borderRadius:10,padding:14,marginBottom:14}}>
                    <div style={{fontSize:11,color:"#a78bfa",fontWeight:700,marginBottom:10}}>SUCUMBÊNCIA</div>
                    <Pct label="% Sucumbência" value={formC.pctSucumb} onChange={v=>sc("pctSucumb",v)} color="#a78bfa" baseVal={formC.valorAcao||0}/>
                    <div style={{height:1,background:"#2d3748",margin:"8px 0"}}/>
                    {formC.temP1&&<Pct label={`% ${formC.nomeP1||"Parceiro 1"}`} value={formC.p1Suc} onChange={v=>setPS("p1Suc",v)} color="#818cf8" baseVal={(formC.valorAcao||0)*(formC.pctSucumb||0)}/>}
                    {formC.temP2&&<Pct label={`% ${formC.nomeP2||"Parceiro 2"}`} value={formC.p2Suc} onChange={v=>setPS("p2Suc",v)} color="#a78bfa" baseVal={(formC.valorAcao||0)*(formC.pctSucumb||0)}/>}
                    <Pct label="% Delegoo Suc." value={formC.pctDelSuc} onChange={v=>setPS("pctDelSuc",v)} color="#6366f1" baseVal={(formC.valorAcao||0)*(formC.pctSucumb||0)}/>
                  </div>
                  {/* TOTAL A RECEBER - resumo final */}
                  {fmR&&formC.valorAcao>0&&(
                    <div style={{background:"linear-gradient(135deg,#0a1929,#0e2237)",borderRadius:12,padding:16,marginBottom:12,border:"2px solid #1e3a5f"}}>
                      <div style={{fontSize:12,color:"#60a5fa",fontWeight:800,marginBottom:12,textTransform:"uppercase",letterSpacing:0.5}}>💰 TOTAL DELEGOO A RECEBER</div>
                      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
                        <div style={{background:"#0f1117",borderRadius:8,padding:"10px 12px"}}>
                          <div style={{fontSize:10,color:"#64748b",marginBottom:3}}>Restante Hon. Contratuais</div>
                          <div style={{fontSize:15,fontWeight:800,color:"#10b981"}}>{fmt(fmR.rest)}</div>
                          <div style={{fontSize:10,color:"#64748b",marginTop:2}}>{p100(formC.pctRestante||0.18)} × {fmt((formC.valorAcao||0)*(formC.pctHon||0))}</div>
                        </div>
                        <div style={{background:"#0f1117",borderRadius:8,padding:"10px 12px"}}>
                          <div style={{fontSize:10,color:"#64748b",marginBottom:3}}>Sucumbência Delegoo (30%)</div>
                          <div style={{fontSize:15,fontWeight:800,color:"#a78bfa"}}>{fmt(fmR.sucDel)}</div>
                          <div style={{fontSize:10,color:"#64748b",marginTop:2}}>{p100(formC.pctDelSuc||0.3)} × {fmt(fmR.sucTot)}</div>
                        </div>
                      </div>
                      <div style={{background:"#0f1117",borderRadius:8,padding:"12px 14px",display:"flex",justifyContent:"space-between",alignItems:"center",border:"1px solid #1e3a5f"}}>
                        <div>
                          <div style={{fontSize:11,color:"#64748b"}}>TOTAL A RECEBER (Hon. restante + Sucumb.)</div>
                          <div style={{fontSize:10,color:"#4a5568",marginTop:2}}>Antecipado já recebido: {fmt(formC.valorAntecipado>0?formC.valorAntecipado:(formC.valorAcao||0)*(formC.pctHon||0)*(formC.pctAntec||0.15))}</div>
                        </div>
                        <div style={{fontSize:22,fontWeight:900,color:"#60a5fa"}}>{fmt(fmR.rest+fmR.sucDel)}</div>
                      </div>
                      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginTop:8}}>
                        <div style={{background:"#0f1117",borderRadius:8,padding:"8px 12px",textAlign:"center"}}>
                          <div style={{fontSize:10,color:"#64748b",marginBottom:2}}>Guima a receber</div>
                          <div style={{fontSize:14,fontWeight:800,color:"#22d3ee"}}>{fmt((fmR.rest+fmR.sucDel)*(formC.pctGm||0.5))}</div>
                        </div>
                        <div style={{background:"#0f1117",borderRadius:8,padding:"8px 12px",textAlign:"center"}}>
                          <div style={{fontSize:10,color:"#64748b",marginBottom:2}}>Boaro a receber</div>
                          <div style={{fontSize:14,fontWeight:800,color:"#f59e0b"}}>{fmt((fmR.rest+fmR.sucDel)*(formC.pctBo||0.5))}</div>
                        </div>
                      </div>
                    </div>
                  )}

                  {fmR&&formC.valorAcao>0&&(
                    <div style={{background:"#0f1117",borderRadius:12,padding:14,border:"1px solid #2d3748"}}>
                      <div style={{fontSize:10,color:"#64748b",fontWeight:700,marginBottom:10}}>👁 PREVIEW</div>
                      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8}}>
                        {[["Hon.Total",fmR.honTot,"#94a3b8"],["Antecipado",fmR.antec,"#10b981"],["Hon Delegoo",fmR.honDel,"#6366f1"],["Suc Delegoo",fmR.sucDel,"#a78bfa"],["Guima",fmR.honGm+fmR.sucGm,"#22d3ee"],["Boaro",fmR.honBo+fmR.sucBo,"#f59e0b"],["P1 Hon",fmR.honP1,"#818cf8"],["P1 Suc",fmR.sucP1,"#818cf8"]].map(([l,v,c])=>(
                          <div key={l} style={{background:"#1a1d2e",borderRadius:8,padding:"9px 10px"}}><div style={{fontSize:9,color:"#64748b",marginBottom:2}}>{l}</div><div style={{fontSize:12,fontWeight:800,color:c}}>{fmt(v)}</div></div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              )}
              <div style={{display:"flex",gap:10,marginTop:20}}>
                <button onClick={()=>setShowFC(false)} style={{flex:1,background:"transparent",color:"#64748b",border:"1px solid #2d3748",borderRadius:10,padding:12,fontWeight:700,cursor:"pointer"}}>Cancelar</button>
                <button onClick={saveC} style={{flex:2,background:"linear-gradient(135deg,#4f46e5,#7c3aed)",color:"#fff",border:"none",borderRadius:10,padding:12,fontWeight:800,fontSize:14,cursor:"pointer"}}>{editC?"💾 Salvar":"✅ Adicionar"}</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ══════════════════════════════════════════════════════════
          MODAL LANÇAMENTO
      ══════════════════════════════════════════════════════════ */}
      {showFL&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.85)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,padding:16}}>
          <div style={{background:"#1a1d2e",borderRadius:16,border:"1px solid #2d3748",width:"100%",maxWidth:520,maxHeight:"90vh",overflowY:"auto"}}>
            <div style={{padding:"14px 20px",borderBottom:"1px solid #2d3748",display:"flex",justifyContent:"space-between",alignItems:"center",position:"sticky",top:0,background:"#1a1d2e",zIndex:1}}>
              <div style={{fontWeight:800,fontSize:15,color:"#f1f5f9"}}>{editL?"✏️ Editar Lançamento":"➕ Novo Lançamento"}</div>
              <button onClick={()=>setShowFL(false)} style={{background:"#2d3748",border:"none",color:"#94a3b8",borderRadius:8,width:30,height:30,cursor:"pointer",fontSize:16}}>✕</button>
            </div>
            <div style={{padding:20}}>
              <div style={{marginBottom:14}}>
                <Lbl ch="TIPO DE LANÇAMENTO"/>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6}}>
                  {Object.entries(TIPO_FIN_LABELS).map(([k,v])=>(
                    <button key={k} onClick={()=>{sl("tipo",k);sl("cat",(CAT_FIN[k]||[])[0]||"");}} style={{padding:"10px 12px",borderRadius:8,border:"2px solid",borderColor:formL.tipo===k?v.color:"#2d3748",background:formL.tipo===k?v.bg:"transparent",color:formL.tipo===k?v.color:"#64748b",fontWeight:700,cursor:"pointer",fontSize:12,textAlign:"left"}}>
                      {v.icon} {v.label}
                    </button>
                  ))}
                </div>
              </div>
              <div style={{marginBottom:12}}><Lbl ch="CATEGORIA"/><select value={formL.cat} onChange={e=>sl("cat",e.target.value)} style={sel}>{(CAT_FIN[formL.tipo]||[]).map(c=><option key={c} value={c}>{c}</option>)}</select></div>
              <div style={{marginBottom:12}}><Lbl ch="DESCRIÇÃO"/><input value={formL.desc} onChange={e=>sl("desc",e.target.value)} placeholder="Ex: Aluguel escritório, Honorários SCHELLIN..." style={inp}/></div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:12}}>
                <div><Lbl ch="VALOR (R$)"/><input type="number" value={formL.valor} onChange={e=>sl("valor",e.target.value)} placeholder="0,00" style={inp}/></div>
                <div><Lbl ch="DATA"/><input type="date" value={formL.data} onChange={e=>sl("data",e.target.value)} style={inp}/></div>
              </div>
              {formL.valor>0&&(
                <div style={{background:"#0f1117",borderRadius:10,padding:12,marginBottom:14,border:`1px solid ${TIPO_FIN_LABELS[formL.tipo]?.color||"#2d3748"}44`}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                    <div><Badge tipo={formL.tipo}/><div style={{fontSize:12,color:"#94a3b8",marginTop:4}}>{formL.cat} · {formL.desc||"—"}</div></div>
                    <div style={{fontSize:20,fontWeight:900,color:isEnt(formL.tipo)?"#10b981":"#ef4444"}}>{isEnt(formL.tipo)?"+":"-"}{fmt(parseFloat(formL.valor)||0)}</div>
                  </div>
                </div>
              )}
              <div style={{display:"flex",gap:10}}>
                <button onClick={()=>setShowFL(false)} style={{flex:1,background:"transparent",color:"#64748b",border:"1px solid #2d3748",borderRadius:10,padding:12,fontWeight:700,cursor:"pointer"}}>Cancelar</button>
                <button onClick={saveL} style={{flex:2,background:"linear-gradient(135deg,#10b981,#059669)",color:"#fff",border:"none",borderRadius:10,padding:12,fontWeight:800,fontSize:14,cursor:"pointer"}}>{editL?"💾 Salvar":"✅ Adicionar"}</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// firebase v2
